#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=5e4+10,M=1e6+10;
struct Edges
{
	int u,v,w;inline Edges(int uu=0,int vv=0,int ww=0){u=uu;v=vv;w=ww;}
	inline bool operator<(const Edges &Q)const{return w<Q.w;}
}E[M],sav_E[M];
vector<int> qwq;int n,m,s,k,fa[N],sav_fa[N],ans;
inline int fnd(int x){return fa[x]==x?x:fa[x]=fnd(fa[x]);}
inline bool check(int x)
{
	memcpy(sav_E,E,sizeof(E));ans=0;
	for(int v:qwq)E[v].w+=x;sort(E+1,E+m+1);
	memcpy(sav_fa,fa,sizeof(fa));int sn=0;
	rep(1,m,i)
	{
		int u=fnd(E[i].u),v=fnd(E[i].v);if(u==v)continue;
		fa[v]=u;ans+=E[i].w;if(E[i].u==s||E[i].v==s)
		{
//			printf("dee %d %d %d\n",E[i].u,E[i].v,E[i].w);
			++sn;
		}
	}
//	printf("%d\n",sn);
	memcpy(E,sav_E,sizeof(sav_E));
	memcpy(fa,sav_fa,sizeof(sav_fa));
	return sn<=k;
}
int main()
{
	n=read();m=read();s=read();k=read();rep(1,n,i)fa[i]=i;
	rep(1,m,i){int u=read(),v=read(),w=read();E[i]=Edges(u,v,w);if(u==s||v==s)qwq.push_back(i);}
	if(int(qwq.size())<k){puts("Impossible");return 0;}
	long long l=-1e7,r=1e7,mid;long long res=-4e18;
	while(l<=r)check(mid=(l+r)>>1)?(r=mid-1,res=ans-1ll*k*mid):(l=mid+1);
	if(res==(long long)(-4e18)){puts("Impossible");return 0;}
	printf("%lld\n",res);return 0;
}
